<script>
(function () {
  const empresas = [
    { id: 1, empresa: 'Reginas', rfc: '-', baseDatos: '-', ubicacion: 'Central', estado: 'Activa', creacion: '13/06/2026' },
    { id: 2, empresa: 'CoffeeSoft', rfc: '-', baseDatos: '-', ubicacion: '-', estado: 'Activa', creacion: '06/06/2026' },
    { id: 3, empresa: 'Acme Corp', rfc: 'ACM123456789', baseDatos: 'db_acme', ubicacion: 'Norte', estado: 'Inactiva', creacion: '01/05/2026' },
    { id: 4, empresa: 'Globex', rfc: 'GLB987654321', baseDatos: 'db_globex', ubicacion: 'Sur', estado: 'Activa', creacion: '20/04/2026' },
    { id: 5, empresa: 'Initech', rfc: 'INI555555555', baseDatos: 'db_initech', ubicacion: 'Central', estado: 'Activa', creacion: '15/03/2026' }
  ];

  let currentPage = 1;
  const rowsPerPage = 2;
  let sortKey = '';
  let sortDirection = 1; // 1 asc, -1 desc
  let filteredData = [...empresas];

  const tableBody = document.getElementById('empresasTableBody');
  const searchInput = document.getElementById('searchInput');
  const estadoFilter = document.getElementById('estadoFilter');
  const paginationInfo = document.getElementById('paginationInfo');
  const paginationPages = document.getElementById('paginationPages');
  const btnAnterior = document.getElementById('btnAnterior');
  const btnSiguiente = document.getElementById('btnSiguiente');
  const modalEmpresa = document.getElementById('modalEmpresa');
  const btnNuevaEmpresa = document.getElementById('btnNuevaEmpresa');
  const formNuevaEmpresa = document.getElementById('formNuevaEmpresa');

  function formatDash(value) {
    return value === '-' || !value ? '<span class="text-slate-500">-</span>' : value;
  }

  function getStatusBadge(estado) {
    const isActive = estado === 'Activa';
    const base = isActive ? 'bg-emerald-500/15 text-emerald-400 border-emerald-500/20' : 'bg-rose-500/15 text-rose-400 border-rose-500/20';
    return `<span class="inline-flex items-center px-2.5 py-1 rounded-md text-xs font-medium border ${base}">${estado}</span>`;
  }

  function renderTable() {
    const start = (currentPage - 1) * rowsPerPage;
    const end = start + rowsPerPage;
    const pageData = filteredData.slice(start, end);

    tableBody.innerHTML = pageData.length
      ? pageData.map(item => `
        <tr class="hover:bg-slate-700/30 transition-colors">
          <td class="px-4 py-3.5 text-slate-200 font-medium">${item.empresa}</td>
          <td class="px-4 py-3.5 font-[JetBrains_Mono] text-slate-300">${formatDash(item.rfc)}</td>
          <td class="px-4 py-3.5 text-slate-300">${formatDash(item.baseDatos)}</td>
          <td class="px-4 py-3.5 text-slate-300">${formatDash(item.ubicacion)}</td>
          <td class="px-4 py-3.5">${getStatusBadge(item.estado)}</td>
          <td class="px-4 py-3.5 font-[JetBrains_Mono] text-slate-300">${item.creacion}</td>
          <td class="px-4 py-3.5">
            <div class="flex items-center justify-center gap-2">
              <button class="p-1.5 rounded-md bg-[#B85C4F] hover:bg-[#A34F43] text-white transition-colors" title="Editar">
                <i data-lucide="pencil" class="w-4 h-4"></i>
              </button>
              <button class="p-1.5 rounded-md bg-slate-700 hover:bg-slate-600 text-slate-200 transition-colors" title="Configuración">
                <i data-lucide="settings" class="w-4 h-4"></i>
              </button>
            </div>
          </td>
        </tr>
      `).join('')
      : `<tr><td colspan="7" class="px-4 py-10 text-center text-slate-400">No se encontraron registros</td></tr>`;

    const total = filteredData.length;
    const from = total ? start + 1 : 0;
    const to = Math.min(end, total);
    paginationInfo.textContent = total
      ? `Mostrando del (${from} al ${to}) de un total de ${total} registros`
      : 'No hay registros para mostrar';

    renderPagination();
    refreshIcons();
  }

  function renderPagination() {
    const totalPages = Math.ceil(filteredData.length / rowsPerPage) || 1;
    let html = '';
    for (let i = 1; i <= totalPages; i++) {
      html += `<button data-page="${i}" class="px-4 py-2 rounded-lg text-sm font-medium transition-colors ${i === currentPage ? 'bg-[#B85C4F] text-white' : 'border border-slate-600 bg-slate-800 text-slate-300 hover:bg-slate-700'}">${i}</button>`;
    }
    paginationPages.innerHTML = html;
    btnAnterior.disabled = currentPage === 1;
    btnSiguiente.disabled = currentPage === totalPages || totalPages === 0;
  }

  function refreshIcons() {
    if (window.lucide) lucide.createIcons();
  }

  function applyFilters() {
    const term = searchInput.value.toLowerCase().trim();
    const estado = estadoFilter.value;

    filteredData = empresas.filter(item => {
      const matchesSearch = !term ||
        item.empresa.toLowerCase().includes(term) ||
        item.rfc.toLowerCase().includes(term) ||
        item.baseDatos.toLowerCase().includes(term) ||
        item.ubicacion.toLowerCase().includes(term);
      const matchesEstado = estado === 'todos' || item.estado.toLowerCase() === estado;
      return matchesSearch && matchesEstado;
    });

    if (sortKey) {
      filteredData.sort((a, b) => {
        const valA = (a[sortKey] || '').toString().toLowerCase();
        const valB = (b[sortKey] || '').toString().toLowerCase();
        if (valA < valB) return -1 * sortDirection;
        if (valA > valB) return 1 * sortDirection;
        return 0;
      });
    }

    currentPage = 1;
    renderTable();
  }

  // Events
  searchInput.addEventListener('input', applyFilters);
  estadoFilter.addEventListener('change', applyFilters);

  document.querySelectorAll('th[data-sort]').forEach(th => {
    th.addEventListener('click', () => {
      const key = th.dataset.sort;
      if (sortKey === key) {
        sortDirection *= -1;
      } else {
        sortKey = key;
        sortDirection = 1;
      }
      applyFilters();
    });
  });

  btnAnterior.addEventListener('click', () => {
    if (currentPage > 1) {
      currentPage--;
      renderTable();
    }
  });

  btnSiguiente.addEventListener('click', () => {
    const totalPages = Math.ceil(filteredData.length / rowsPerPage);
    if (currentPage < totalPages) {
      currentPage++;
      renderTable();
    }
  });

  paginationPages.addEventListener('click', e => {
    const pageBtn = e.target.closest('[data-page]');
    if (pageBtn) {
      currentPage = parseInt(pageBtn.dataset.page, 10);
      renderTable();
    }
  });

  // Tabs
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.tab-btn').forEach(b => {
        b.classList.remove('active', 'bg-slate-700', 'text-slate-100');
        b.classList.add('text-slate-400');
      });
      btn.classList.add('active', 'bg-slate-700', 'text-slate-100');
      btn.classList.remove('text-slate-400');
    });
  });

  // Modal
  function openModal() {
    modalEmpresa.classList.remove('hidden');
    document.body.style.overflow = 'hidden';
    refreshIcons();
  }

  function closeModal() {
    modalEmpresa.classList.add('hidden');
    document.body.style.overflow = '';
  }

  btnNuevaEmpresa.addEventListener('click', openModal);
  modalEmpresa.querySelectorAll('[data-close-modal]').forEach(el => el.addEventListener('click', closeModal));

  formNuevaEmpresa.addEventListener('submit', e => {
    e.preventDefault();
    const formData = new FormData(formNuevaEmpresa);
    const today = new Date();
    const dateStr = today.toLocaleDateString('es-MX', { day: '2-digit', month: '2-digit', year: 'numeric' }).replace(/\//g, '/');
    const newEmpresa = {
      id: empresas.length + 1,
      empresa: formData.get('empresa'),
      rfc: formData.get('rfc') || '-',
      baseDatos: formData.get('baseDatos') || '-',
      ubicacion: formData.get('ubicacion') || '-',
      estado: formData.get('estado'),
      creacion: dateStr
    };
    empresas.unshift(newEmpresa);
    formNuevaEmpresa.reset();
    closeModal();
    applyFilters();
  });

  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && !modalEmpresa.classList.contains('hidden')) {
      closeModal();
    }
  });

  // Init
  applyFilters();
})();
</script>
